from sys import stdin
input = stdin.readline

def solve():
    n, d = map(int, input().split())
    a = list(map(int, input().split()))

    nxt = [(i - d) % n for i in range(n)]

    f = [-1] * n
    visited = [0] * n

    for start in range(n):
        if f[start] != -1:
            continue
        path = []
        cur = start
        while f[cur] == -1 and visited[cur] == 0:
            visited[cur] = start + 1
            path.append(cur)
            cur = nxt[cur]

        if f[cur] != -1:
            for node in reversed(path):
                f[node] = 0 if a[node] == 0 else 1 + f[nxt[node]]
        else:
            # found cycle
            cycle_start = cur
            idx = path.index(cycle_start)
            cycle = path[idx:]
            tail = path[:idx]
            if all(a[c] == 1 for c in cycle):
                print(-1)
                return
            # compute f for cycle nodes
            L = len(cycle)
            # find a 0 in cycle
            for ci in range(L):
                if a[cycle[ci]] == 0:
                    zero_pos = ci
                    break
            for ci in range(L):
                node = cycle[ci]
                if a[node] == 0:
                    f[node] = 0
                else:
                    dist = (zero_pos - ci) % L
                    f[node] = dist
            for node in reversed(tail):
                f[node] = 0 if a[node] == 0 else 1 + f[nxt[node]]

    print(max(f))

